proof:
-- For n ≥ 1: We need log(n+1) ≤ H_n. This can be proved by induction: log(n+1) - log(n) = log(1 + 1/n) ≤ 1/n.
have h_ind : Real.log (n + 1) ≤ ∑ k ∈ Icc 1 n, (k : ℝ)⁻¹ := by
  have h_ind : ∀ k : ℕ, 1 ≤ k → Real.log (k + 1) - Real.log k ≤ 1 / k := by
    intro k hk; rw [ ← Real.log_div ( by positivity ) ( by positivity ) ] ; ring_nf; (
    exact le_trans ( Real.log_le_sub_one_of_pos ( by positivity ) ) ( by nlinarith [ mul_inv_cancel₀ ( by positivity : ( k : ℝ ) ≠ 0 ) ] ));
  exact Nat.recOn n ( by norm_num ) fun n ihn => by have := h_ind ( n + 1 ) ( by linarith ) ; norm_num [ Finset.sum_Ioc_succ_top, (Nat.succ_eq_succ ▸ Finset.Icc_succ_left_eq_Ioc) ] at * ; linarith;
by_cases hn : n = 0;
· norm_num [ hn ] at *;
  exact le_trans ( Real.log_nonpos hxge hxlt.le ) ( Finset.sum_nonneg fun _ _ => by positivity );
· exact le_trans ( Real.log_le_log ( by linarith [ show ( n : ℝ ) ≥ 1 by exact Nat.one_le_cast.mpr ( Nat.pos_of_ne_zero hn ) ] ) hxlt.le ) h_ind

